#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";abi=x86_64;serial=emulator-5554;timeout=30;apk=;while (($#));do case "$1" in --android-abi)abi="${2:?}";shift 2;;--serial)serial="${2:?}";shift 2;;--timeout-seconds)timeout="${2:?}";shift 2;;--apk)apk="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";apk="${apk:-$ARCHPHENE_ROOT/prototypes/secrets-capability-probe/out-$abi/archphene-secrets-probe.apk}";archphene_require_file "$apk";package=org.archphene.secretsprobe;archphene_adb_run install -r "$apk" >/dev/null;archphene_adb_run logcat -c;archphene_adb_run shell am start -W -n "$package/org.archphene.bridge.SecretsProbeActivity" >/dev/null;log="$(archphene_wait_log 'Secrets broker listening' "$timeout" 'ArchpheneCapabilities AndroidRuntime *:S')";[[ "$log" != *'FATAL EXCEPTION'* ]] || archphene_die 'secrets probe crashed';page="$(archphene_adb_run shell getconf PAGESIZE|tr -d '\r')";records="$(archphene_adb_run shell run-as "$package" find files/secrets -type f 2>/dev/null || true)";! grep -q 'archphene-secret-value'<<<"$records" || archphene_die 'secret plaintext exposed';archphene_note "Android secrets bridge passed on $serial ($abi, $page-byte pages): encrypted store and broker startup verified."
